public class LongestRepeatedSubstring {

    public static String findLongestRepeatedSubstring(String text) {
        if (text == null || text.length() == 0) {
            return "";
        }

        int n = text.length();
        int[] suffixArray = buildSuffixArray(text, n);
        int[] lcp = buildLCP(text, n, suffixArray);
        int maxLength = 0;
        int idx = 0;

        for (int i = 1; i < n; i++) {
            if (lcp[i] > maxLength) {
                maxLength = lcp[i];
                idx = i;
            }
        }

        return maxLength > 0 ? text.substring(suffixArray[idx], suffixArray[idx] + maxLength) : "";
    }

    private static int[] buildSuffixArray(String text, int n) {
        int[] suffixArray = new int[n];
        int[] rank = new int[n];
        int[] temp = new int[n];

        for (int i = 0; i < n; i++) {
            suffixArray[i] = i;
            rank[i] = text.charAt(i);
        }

        for (int k = 1; k < n; k *= 2) {
            final int K = k;
            Arrays.sort(suffixArray, (i, j) -> {
                if (rank[i] != rank[j]) {
                    return Integer.compare(rank[i], rank[j]);
                }
                int ri = i + K < n ? rank[i + K] : -1;
                int rj = j + K < n ? rank[j + K] : -1;
                return Integer.compare(ri, rj);
            });

            temp[suffixArray[0]] = 0;
            for (int i = 1; i < n; i++) {
                temp[suffixArray[i]] = temp[suffixArray[i - 1]];
                if (rank[suffixArray[i]] != rank[suffixArray[i - 1]]
                    || (suffixArray[i] + k < n ? rank[suffixArray[i] + k] : -1) != (suffixArray[i - 1] + k < n ? rank[suffixArray[i - 1] + k] : -1)) {
                    temp[suffixArray[i]]++;
                }
            }
            System.arraycopy(temp, 0, rank, 0, n);
        }

        return suffixArray;
    }

    private static int[] buildLCP(String text, int n, int[] suffixArray) {
        int[] rank = new int[n];
        int[] lcp = new int[n];

        for (int i = 0; i < n; i++) {
            rank[suffixArray[i]] = i;
        }

        int h = 0;
        for (int i = 0; i < n; i++) {
            if (rank[i] > 0) {
                int j = suffixArray[rank[i] - 1];
                while (i + h < n && j + h < n && text.charAt(i + h) == text.charAt(j + h)) {
                    h++;
                }
                lcp[rank[i]] = h;
                if (h > 0) {
                    h--;
                }
            }
        }

        return lcp;
    }

    public static void main(String[] args) {
        System.out.println(findLongestRepeatedSubstring("banana")); // Output: "ana"
    }
}

