// Function to compute suffix array
std::vector<int> computeSuffixArray(const std::string& text) {
    int n = text.size();
    std::vector<int> suffixArray(n), rank(n);
    for (int i = 0; i < n; i++) {
        suffixArray[i] = i;
        rank[i] = text[i];
    }

    for (int k = 1; k < n; k *= 2) {
        auto compare = [&](int a, int b) {
            if (rank[a] != rank[b]) return rank[a] < rank[b];
            int ra = (a + k < n) ? rank[a + k] : -1;
            int rb = (b + k < n) ? rank[b + k] : -1;
            return ra < rb;
        };
        std::sort(suffixArray.begin(), suffixArray.end(), compare);

        std::vector<int> newRank(n);
        newRank[suffixArray[0]] = 0;
        for (int i = 1; i < n; i++) {
            newRank[suffixArray[i]] = newRank[suffixArray[i - 1]] + compare(suffixArray[i - 1], suffixArray[i]);
        }
        rank = newRank;
    }

    return suffixArray;
}

// Function to compute the longest common prefix array
std::vector<int> computeLCPArray(const std::string& text, const std::vector<int>& suffixArray) {
    int n = text.size();
    std::vector<int> rank(n), lcp(n - 1);
    for (int i = 0; i < n; i++) rank[suffixArray[i]] = i;

    int h = 0;
    for (int i = 0; i < n; i++) {
        if (rank[i] > 0) {
            int j = suffixArray[rank[i] - 1];
            while (i + h < n && j + h < n && text[i + h] == text[j + h]) h++;
            lcp[rank[i] - 1] = h;
            if (h > 0) h--;
        }
    }

    return lcp;
}

// Main function to find the longest repeated substring
std::string longest_repeated_substring(const std::string& s) {
    int n = s.size();
    if (n == 0) return "";

    std::vector<int> suffixArray = computeSuffixArray(s);
    std::vector<int> lcp = computeLCPArray(s, suffixArray);

    int maxLength = 0;
    int startIndex = 0;

    for (int i = 0; i < lcp.size(); i++) {
        if (lcp[i] > maxLength) {
            maxLength = lcp[i];
            startIndex = suffixArray[i];
        }
    }

