pub fn merge_sort_list<T: PartialOrd + Clone>(head: Option<Box<ListNode<T>>>) -> Option<Box<ListNode<T>>> {
    if head.is_none() || head.as_ref().unwrap().next.is_none() {
        return head;
    }

    let (left, right) = split(head);
    let left_sorted = merge_sort_list(left);
    let right_sorted = merge_sort_list(right);
    merge(left_sorted, right_sorted)
}

fn split<T>(mut head: Option<Box<ListNode<T>>>) -> (Option<Box<ListNode<T>>>, Option<Box<ListNode<T>>>) {
    let mut slow = &mut head;
    let mut fast = head.as_ref();

    while let Some(ref mut f) = fast {
        if f.next.is_none() { break; }
        fast = f.next.as_ref().unwrap().next.as_ref();
        if fast.is_some() { slow = &mut slow.as_mut().unwrap().next; }
    }

    let right = slow.as_mut().map(|n| n.next.take());
    (head, right.unwrap_or(None))
}

fn merge<T: PartialOrd + Clone>(left: Option<Box<ListNode<T>>>, right: Option<Box<ListNode<T>>>) -> Option<Box<ListNode<T>>> {
    match (left, right) {
        (None, r) => r,
        (l, None) => l,
        (Some(mut l), Some(mut r)) => {
            if l.val <= r.val {
                l.next = merge(l.next.take(), Some(r));
                Some(l)
            } else {
                r.next = merge(Some(l), r.next.take());
                Some(r)
            }
        }
    }
}

