#include <iostream>

int factorial(int n) {
    if (n < 0) {
        std::cerr << "Error: Negative input not allowed." << std::endl;
        return -1; // Indication of error
    }
    int result = 1;
    for (int i = 1; i <= n; ++i) {
        result *= i;
    }
    return result;
}

